// ===================================================
// WF-01-A: getClasses - 클래스 목록 조회
// 레거시/신규 상태값을 모두 읽되 응답은 정규화된 값으로 반환
// ===================================================

const input = $input.first().json;
const body = input.body || input;

function splitValues(raw) {
  return String(raw || '')
    .split(',')
    .map((item) => String(item || '').replace(/\s+/g, ' ').trim())
    .filter((item) => item.length > 0);
}

function unique(values) {
  const seen = new Set();
  const result = [];
  for (const value of values) {
    if (!value || seen.has(value)) continue;
    seen.add(value);
    result.push(value);
  }
  return result;
}

function normalizeLevel(raw) {
  const text = String(raw || '').replace(/\s+/g, ' ').trim();
  const upper = text.toUpperCase();
  const lower = text.toLowerCase();
  if (!text) return '';
  if (upper === 'BEGINNER' || lower === 'beginner' || lower === 'basic' || text.includes('입문') || text.includes('초급')) return 'BEGINNER';
  if (upper === 'INTERMEDIATE' || lower === 'intermediate' || text.includes('중급')) return 'INTERMEDIATE';
  if (upper === 'ADVANCED' || lower === 'advanced' || lower === 'expert' || text.includes('심화') || text.includes('고급')) return 'ADVANCED';
  if (upper === 'ALL_LEVELS' || text.includes('전체')) return 'ALL_LEVELS';
  return upper;
}

function normalizeRegion(raw) {
  const text = String(raw || '').replace(/\s+/g, ' ').trim();
  if (!text) return '';
  const upper = text.toUpperCase();
  const primary = text.split(' ')[0];
  const map = {
    '서울': 'SEOUL',
    '경기': 'GYEONGGI',
    '경기도': 'GYEONGGI',
    '인천': 'INCHEON',
    '부산': 'BUSAN',
    '대구': 'DAEGU',
    '대전': 'DAEJEON',
    '광주': 'GWANGJU',
    '울산': 'ULSAN',
    '세종': 'SEJONG',
    '강원': 'GANGWON',
    '강원도': 'GANGWON',
    '충북': 'CHUNGBUK',
    '충청북도': 'CHUNGBUK',
    '충남': 'CHUNGNAM',
    '충청남도': 'CHUNGNAM',
    '전북': 'JEONBUK',
    '전라북도': 'JEONBUK',
    '전남': 'JEONNAM',
    '전라남도': 'JEONNAM',
    '경북': 'GYEONGBUK',
    '경상북도': 'GYEONGBUK',
    '경남': 'GYEONGNAM',
    '경상남도': 'GYEONGNAM',
    '제주': 'JEJU',
    '제주도': 'JEJU',
    '온라인': 'ONLINE',
    '기타': 'OTHER'
  };
  if (map[text]) return map[text];
  if (map[primary]) return map[primary];
  if (upper === 'ONLINE' || lowerContains(text, 'online')) return 'ONLINE';
  return map[upper] || upper;
}

function lowerContains(text, keyword) {
  return String(text || '').toLowerCase().includes(String(keyword || '').toLowerCase());
}

const categories = unique(splitValues(body.category));
const levels = unique(splitValues(body.level || body.difficulty).map(normalizeLevel).filter(Boolean));
const classTypes = unique(splitValues(body.type));
const regions = unique(splitValues(body.region).map(normalizeRegion).filter(Boolean));
const sort = String(body.sort || 'latest').trim() || 'latest';
const page = Math.max(parseInt(body.page, 10) || 1, 1);
const limit = Math.min(Math.max(parseInt(body.limit, 10) || 20, 1), 50);
const maxPrice = Math.min(Math.max(parseInt(body.maxPrice, 10) || 200000, 0), 200000000);
const search = String(body.search || body.q || '').replace(/\s+/g, ' ').trim();

return [{
  json: {
    page,
    limit,
    sort,
    _params: {
      categories,
      levels,
      classTypes,
      regions,
      sort,
      page,
      limit,
      maxPrice,
      search
    }
  }
}];

// ===================================================
// 클래스 목록 + 파트너 정보 + 잔여석 조인 + 정규화 + 필터/정렬/페이지네이션
// ===================================================

const classesResponse = $('NocoDB Get Classes').first().json;
const partnersResponse = $('NocoDB Get Partners (Join)').first().json;
const schedulesResponse = $('NocoDB Get Schedules for List').first().json;
const params = $('Parse getClasses Params').first().json._params || {};

const classesList = classesResponse.list || [];
const partnersList = partnersResponse.list || [];
const schedulesList = schedulesResponse.list || [];

function normalizeStatus(raw) {
  const text = String(raw || '').replace(/\s+/g, ' ').trim();
  const upper = text.toUpperCase();
  if (!text) return 'DRAFT';
  if (upper === 'ACTIVE' || text.toLowerCase() === 'active') return 'ACTIVE';
  if (upper === 'PAUSED' || text.toLowerCase() === 'paused') return 'PAUSED';
  if (upper === 'PENDING_REVIEW' || upper === 'INACTIVE' || text.toLowerCase() === 'pending') return 'PENDING_REVIEW';
  if (upper === 'REJECTED' || text.toLowerCase() === 'closed') return 'REJECTED';
  if (upper === 'ARCHIVED') return 'ARCHIVED';
  return upper;
}

function normalizeLevel(raw) {
  const text = String(raw || '').replace(/\s+/g, ' ').trim();
  const upper = text.toUpperCase();
  const lower = text.toLowerCase();
  if (!text) return '';
  if (upper === 'BEGINNER' || lower === 'beginner' || lower === 'basic' || text.includes('입문') || text.includes('초급')) return 'BEGINNER';
  if (upper === 'INTERMEDIATE' || lower === 'intermediate' || text.includes('중급')) return 'INTERMEDIATE';
  if (upper === 'ADVANCED' || lower === 'advanced' || lower === 'expert' || text.includes('심화') || text.includes('고급')) return 'ADVANCED';
  if (upper === 'ALL_LEVELS' || text.includes('전체')) return 'ALL_LEVELS';
  return upper;
}

function normalizeRegion(rawRegion, rawLocation, rawType) {
  const fromRegion = String(rawRegion || '').replace(/\s+/g, ' ').trim();
  const text = fromRegion || String(rawLocation || '').replace(/\s+/g, ' ').trim();
  const type = String(rawType || '').replace(/\s+/g, ' ').trim();
  const upper = text.toUpperCase();
  const primary = text.split(' ')[0];
  const map = {
    '서울': 'SEOUL',
    '경기': 'GYEONGGI',
    '경기도': 'GYEONGGI',
    '인천': 'INCHEON',
    '부산': 'BUSAN',
    '대구': 'DAEGU',
    '대전': 'DAEJEON',
    '광주': 'GWANGJU',
    '울산': 'ULSAN',
    '세종': 'SEJONG',
    '강원': 'GANGWON',
    '강원도': 'GANGWON',
    '충북': 'CHUNGBUK',
    '충청북도': 'CHUNGBUK',
    '충남': 'CHUNGNAM',
    '충청남도': 'CHUNGNAM',
    '전북': 'JEONBUK',
    '전라북도': 'JEONBUK',
    '전남': 'JEONNAM',
    '전라남도': 'JEONNAM',
    '경북': 'GYEONGBUK',
    '경상북도': 'GYEONGBUK',
    '경남': 'GYEONGNAM',
    '경상남도': 'GYEONGNAM',
    '제주': 'JEJU',
    '제주도': 'JEJU',
    '온라인': 'ONLINE',
    '기타': 'OTHER'
  };
  if (type.includes('온라인') || text.includes('온라인') || upper === 'ONLINE' || upper.includes('ONLINE')) return 'ONLINE';
  if (!text) return '';
  if (map[text]) return map[text];
  if (map[primary]) return map[primary];
  return map[upper] || upper;
}

function normalizePartnerGrade(raw) {
  const upper = String(raw || '').toUpperCase().trim();
  const alias = { SILVER: 'BLOOM', GOLD: 'GARDEN', PLATINUM: 'ATELIER' };
  return alias[upper] || upper;
}

function hasRegionMatch(classRegion, filterRegions) {
  if (!filterRegions || filterRegions.length === 0) return true;
  if (!classRegion) return false;
  if (filterRegions.includes(classRegion)) return true;

  if (filterRegions.includes('OTHER')) {
    const standard = ['SEOUL','GYEONGGI','INCHEON','BUSAN','DAEGU','DAEJEON','GWANGJU','ULSAN','SEJONG','GANGWON','CHUNGBUK','CHUNGNAM','JEONBUK','JEONNAM','GYEONGBUK','GYEONGNAM','JEJU','ONLINE'];
    return standard.indexOf(classRegion) === -1;
  }

  return false;
}

const today = new Date().toISOString().slice(0, 10);
const remainingMap = {};
for (const s of schedulesList) {
  const cid = s.class_id || '';
  if (!cid || s.schedule_date < today) continue;
  const remaining = Math.max((Number(s.capacity) || 0) - (Number(s.booked_count) || 0), 0);
  if (!remainingMap[cid]) {
    remainingMap[cid] = { total_remaining: 0, schedule_count: 0, next_date: s.schedule_date };
  }
  remainingMap[cid].total_remaining += remaining;
  remainingMap[cid].schedule_count += 1;
  if (s.schedule_date < remainingMap[cid].next_date) {
    remainingMap[cid].next_date = s.schedule_date;
  }
}

const partnerMap = {};
for (const p of partnersList) {
  partnerMap[p.partner_code] = {
    partner_name: p.partner_name || '',
    grade: normalizePartnerGrade(p.grade || ''),
    location: p.location || '',
    avg_rating: Number(p.avg_rating) || 0
  };
}

let classes = classesList.map((c) => {
  let partnerCode = '';
  if (Array.isArray(c.partner_code) && c.partner_code.length > 0) {
    partnerCode = c.partner_code[0].partner_code || c.partner_code[0].Title || c.partner_code[0].Id || '';
  } else if (typeof c.partner_code === 'string') {
    partnerCode = c.partner_code;
  }

  const partnerInfo = partnerMap[partnerCode] || { partner_name: '', grade: '', location: '', avg_rating: 0 };
  const status = normalizeStatus(c.status || '');
  const level = normalizeLevel(c.level || '');
  const region = normalizeRegion(c.region || '', c.location || '', c.type || '');
  const price = Number(c.price) || 0;

  return {
    class_id: c.class_id || '',
    makeshop_product_id: c.makeshop_product_id || '',
    class_name: c.class_name || '',
    category: c.category || '',
    level,
    price,
    duration_min: Number(c.duration_min) || 0,
    max_students: Number(c.max_students) || 0,
    thumbnail_url: c.thumbnail_url || '',
    location: c.location || '',
    region,
    tags: c.tags || '',
    type: c.type || '',
    status,
    class_count: Number(c.class_count) || 0,
    avg_rating: Number(c.avg_rating) || 0,
    partner_name: partnerInfo.partner_name,
    partner_code: partnerCode,
    partner_grade: partnerInfo.grade,
    kit_enabled: Number(c.kit_enabled) || 0,
    total_remaining: (remainingMap[c.class_id] || {}).total_remaining || 0,
    schedule_count: (remainingMap[c.class_id] || {}).schedule_count || 0,
    next_date: (remainingMap[c.class_id] || {}).next_date || ''
  };
});

classes = classes.filter((c) => c.status === 'ACTIVE');

if (params.categories && params.categories.length > 0) {
  classes = classes.filter((c) => params.categories.includes(c.category || ''));
}
if (params.levels && params.levels.length > 0) {
  classes = classes.filter((c) => params.levels.includes(c.level || ''));
}
if (params.classTypes && params.classTypes.length > 0) {
  classes = classes.filter((c) => params.classTypes.includes(c.type || ''));
}
if (params.regions && params.regions.length > 0) {
  classes = classes.filter((c) => hasRegionMatch(c.region, params.regions));
}
if (params.maxPrice && params.maxPrice < 200000000) {
  classes = classes.filter((c) => (Number(c.price) || 0) <= params.maxPrice);
}
if (params.search) {
  const query = params.search.toLowerCase();
  classes = classes.filter((c) => {
    return [c.class_name, c.partner_name, c.category, c.location, c.tags]
      .join(' ')
      .toLowerCase()
      .includes(query);
  });
}

switch (params.sort) {
  case 'popular':
    classes.sort((a, b) => (b.class_count || 0) - (a.class_count || 0));
    break;
  case 'rating':
    classes.sort((a, b) => (b.avg_rating || 0) - (a.avg_rating || 0));
    break;
  case 'price_asc':
    classes.sort((a, b) => (a.price || 0) - (b.price || 0));
    break;
  case 'price_desc':
    classes.sort((a, b) => (b.price || 0) - (a.price || 0));
    break;
  case 'latest':
  default:
    classes.sort((a, b) => String(b.class_id || '').localeCompare(String(a.class_id || '')));
    break;
}

const totalCount = classes.length;
const limit = params.limit || 20;
const page = params.page || 1;
const totalPages = Math.max(Math.ceil(totalCount / limit), 1);
const startIdx = (page - 1) * limit;
const pagedClasses = classes.slice(startIdx, startIdx + limit);

return [{
  json: {
    success: true,
    data: {
      classes: pagedClasses,
      page,
      limit,
      total: totalCount,
      totalPages
    },
    timestamp: new Date().toISOString()
  }
}];

// ===================================================
// WF-01-B: getClassDetail 파라미터 검증
// ===================================================

const body = $input.first().json.body;
const classId = (body.id || '').trim();

if (!classId) {
  return [{
    json: {
      _error: true,
      success: false,
      error: { code: 'MISSING_PARAMS', message: 'id 파라미터가 필요합니다.' },
      timestamp: new Date().toISOString()
    }
  }];
}

return [{
  json: {
    classId,
    _error: false
  }
}];

// ===================================================
// 클래스 상세 응답 구성
// NocoDB 조회 결과 + 파트너 공개 정보 포함
// ===================================================

const response = $input.first().json;
const classesList = response.list || [];

if (classesList.length === 0) {
  return [{
    json: {
      success: false,
      error: { code: 'CLASS_NOT_FOUND', message: '해당 클래스를 찾을 수 없습니다.' },
      timestamp: new Date().toISOString()
    }
  }];
}

const c = classesList[0];

// 커리큘럼 JSON 파싱
let curriculum = [];
if (c.curriculum_json) {
  try {
    curriculum = JSON.parse(c.curriculum_json);
  } catch (e) {
    // 파싱 실패 시 빈 배열
  }
}

// 이미지 URL 배열 변환 (콤마 구분)
let images = [];
if (c.image_urls) {
  images = c.image_urls.split(',').map(u => u.trim()).filter(u => u.length > 0);
}

// 일정 JSON 파싱
let schedules = [];
if (c.schedules_json) {
  try {
    const parsed = JSON.parse(c.schedules_json);
    if (Array.isArray(parsed)) schedules = parsed;
  } catch (e) {}
}

// 재료 상품 ID 배열
let materialsProductIds = [];
if (c.materials_product_ids) {
  materialsProductIds = c.materials_product_ids.split(',').map(id => id.trim()).filter(id => id.length > 0);
}

// partner_code 추출 (Links 필드 또는 문자열)
let partnerCode = '';
if (Array.isArray(c.partner_code) && c.partner_code.length > 0) {
  partnerCode = c.partner_code[0].partner_code || c.partner_code[0].Title || '';
} else if (typeof c.partner_code === 'string') {
  partnerCode = c.partner_code;
}

return [{
  json: {
    _classData: {
      class_id: c.class_id || '',
      makeshop_product_id: c.makeshop_product_id || '',
      class_name: c.class_name || '',
      category: c.category || '',
      level: c.level || '',
      price: Number(c.price) || 0,
      materials_price: Number(c.materials_price) || 0,
      duration_min: Number(c.duration_min) || 0,
      max_students: Number(c.max_students) || 0,
      description: c.description || '',
      curriculum,
      instructor_bio: c.instructor_bio || '',
      thumbnail_url: c.thumbnail_url || '',
      images,
      youtube_video_id: c.youtube_video_id || '',
      location: c.location || '',
      materials_included: c.materials_included || '',
      materials_product_ids: materialsProductIds,
      tags: c.tags || '',
      type: c.type || '',
      class_count: Number(c.class_count) || 0,
      avg_rating: Number(c.avg_rating) || 0,
      schedules
    },
    _partnerCode: partnerCode,
    _needPartner: true
  }
}];

// ===================================================
// 클래스 상세 + 파트너 + 일정 정보 결합 -> 최종 응답
// ===================================================

const classResponse = $('NocoDB Get Class Detail').first().json;
const classesList = classResponse.list || [];

if (classesList.length === 0) {
  return [{ json: { success: false, error: { code: 'CLASS_NOT_FOUND', message: '해당 클래스를 찾을 수 없습니다.' }, timestamp: new Date().toISOString() } }];
}

function normalizeStatus(raw) {
  const text = String(raw || '').replace(/\s+/g, ' ').trim();
  const upper = text.toUpperCase();
  if (!text) return 'DRAFT';
  if (upper === 'ACTIVE' || text.toLowerCase() === 'active') return 'ACTIVE';
  if (upper === 'PAUSED' || text.toLowerCase() === 'paused') return 'PAUSED';
  if (upper === 'PENDING_REVIEW' || upper === 'INACTIVE' || text.toLowerCase() === 'pending') return 'PENDING_REVIEW';
  if (upper === 'REJECTED' || text.toLowerCase() === 'closed') return 'REJECTED';
  if (upper === 'ARCHIVED') return 'ARCHIVED';
  return upper;
}

function normalizeLevel(raw) {
  const text = String(raw || '').replace(/\s+/g, ' ').trim();
  const upper = text.toUpperCase();
  const lower = text.toLowerCase();
  if (!text) return '';
  if (upper === 'BEGINNER' || lower === 'beginner' || lower === 'basic' || text.includes('입문') || text.includes('초급')) return 'BEGINNER';
  if (upper === 'INTERMEDIATE' || lower === 'intermediate' || text.includes('중급')) return 'INTERMEDIATE';
  if (upper === 'ADVANCED' || lower === 'advanced' || lower === 'expert' || text.includes('심화') || text.includes('고급')) return 'ADVANCED';
  if (upper === 'ALL_LEVELS' || text.includes('전체')) return 'ALL_LEVELS';
  return upper;
}

function normalizeRegion(rawRegion, rawLocation, rawType) {
  const fromRegion = String(rawRegion || '').replace(/\s+/g, ' ').trim();
  const text = fromRegion || String(rawLocation || '').replace(/\s+/g, ' ').trim();
  const type = String(rawType || '').replace(/\s+/g, ' ').trim();
  const upper = text.toUpperCase();
  const primary = text.split(' ')[0];
  const map = {
    '서울': 'SEOUL','경기': 'GYEONGGI','경기도': 'GYEONGGI','인천': 'INCHEON','부산': 'BUSAN','대구': 'DAEGU','대전': 'DAEJEON','광주': 'GWANGJU','울산': 'ULSAN','세종': 'SEJONG','강원': 'GANGWON','강원도': 'GANGWON','충북': 'CHUNGBUK','충청북도': 'CHUNGBUK','충남': 'CHUNGNAM','충청남도': 'CHUNGNAM','전북': 'JEONBUK','전라북도': 'JEONBUK','전남': 'JEONNAM','전라남도': 'JEONNAM','경북': 'GYEONGBUK','경상북도': 'GYEONGBUK','경남': 'GYEONGNAM','경상남도': 'GYEONGNAM','제주': 'JEJU','제주도': 'JEJU','온라인': 'ONLINE','기타': 'OTHER'
  };
  if (type.includes('온라인') || text.includes('온라인') || upper === 'ONLINE' || upper.includes('ONLINE')) return 'ONLINE';
  if (!text) return '';
  if (map[text]) return map[text];
  if (map[primary]) return map[primary];
  return map[upper] || upper;
}

function normalizePartnerGrade(raw) {
  const upper = String(raw || '').toUpperCase().trim();
  const alias = { SILVER: 'BLOOM', GOLD: 'GARDEN', PLATINUM: 'ATELIER' };
  return alias[upper] || upper;
}

function extractBrandUid(raw) {
  const text = String(raw || '').replace(/\s+/g, '').trim();
  const match = text.match(/[?&]branduid=([^&#]+)/i);
  if (match && match[1]) return decodeURIComponent(match[1]);
  if (/^[A-Za-z0-9_-]{4,64}$/.test(text)) return text;
  return '';
}

function normalizeKitProductUrl(raw) {
  const text = String(raw || '').trim();
  if (!text) return '';
  const brandUid = extractBrandUid(text);
  if (brandUid) {
    return '/shop/shopdetail.html?branduid=' + encodeURIComponent(brandUid);
  }
  if (/^https?:\/\//i.test(text) || text.indexOf('/shop/') === 0) {
    return text;
  }
  return '';
}

function normalizeKitItems(raw) {
  let parsed = [];
  try { parsed = raw ? JSON.parse(raw) : []; } catch(e) {}
  if (!Array.isArray(parsed)) return [];
  return parsed.map((item) => ({
    name: String(item && item.name || '').trim(),
    product_url: normalizeKitProductUrl(item && (item.product_url || item.product_code || '')),
    quantity: Math.min(Math.max(parseInt(item && item.quantity, 10) || 1, 1), 99),
    price: Math.max(parseInt(item && item.price, 10) || 0, 0),
    branduid: extractBrandUid(item && (item.product_url || item.product_code || ''))
  })).filter((item) => item.name || item.product_url || item.branduid);
}

const c = classesList[0];
let curriculum = [];
try { if (c.curriculum_json) curriculum = JSON.parse(c.curriculum_json); } catch(e) {}

let images = [];
if (c.image_urls) images = c.image_urls.split(',').map((u) => u.trim()).filter((u) => u.length > 0);

let materialsProductIds = [];
if (c.materials_product_ids) materialsProductIds = c.materials_product_ids.split(',').map((id) => id.trim()).filter((id) => id.length > 0);

const schedulesResponse = $input.first().json;
const schedulesList = schedulesResponse.list || [];
const schedules = schedulesList.map((s) => ({
  schedule_id: s.schedule_id,
  schedule_date: s.schedule_date,
  schedule_time: s.schedule_time,
  capacity: s.capacity || 8,
  booked_count: s.booked_count || 0,
  remaining: (s.capacity || 8) - (s.booked_count || 0)
}));

const partnerResponse = $('NocoDB Get Partner (Detail)').first().json;
const partnerList = partnerResponse.list || [];
let partner = { partner_code: '', partner_name: '', grade: '', location: '', avg_rating: 0, instagram_url: '', portfolio_url: '' };
if (partnerList.length > 0) {
