// ===================================================
// WF-01-C: getCategories - 카테고리 목록 + 건수 집계
// ACTIVE / active 클래스를 모두 포함해 카운트 후 응답합니다.
// ===================================================

const response = $input.first().json;
const classesList = response.list || [];

function normalizeStatus(raw) {
  const text = String(raw || '').replace(/\s+/g, ' ').trim();
  const upper = text.toUpperCase();
  if (upper === 'ACTIVE' || text.toLowerCase() === 'active') return 'ACTIVE';
  return upper;
}

const categories = {};
for (const c of classesList) {
  if (normalizeStatus(c.status || '') !== 'ACTIVE') continue;
  const cat = String(c.category || '').trim();
  if (cat) {
    categories[cat] = (categories[cat] || 0) + 1;
  }
}

const categoryList = Object.entries(categories)
  .map(([name, classCount]) => ({ name, class_count: classCount }))
  .sort((a, b) => b.class_count - a.class_count);

return [{
  json: {
    success: true,
    data: categoryList,
    timestamp: new Date().toISOString()
  }
}];

// ===================================================
// Fallback: 알 수 없는 action 에러 응답
// ===================================================

const action = ($input.first().json.body || {}).action || '';

return [{
  json: {
    success: false,
    error: {
      code: 'INVALID_ACTION',
      message: `알 수 없는 요청입니다: ${action}`
    },
    timestamp: new Date().toISOString()
  }
}];

const workflowStaticData = $getWorkflowStaticData('global');
const cacheStore = workflowStaticData.presscoCache || {};
const entry = cacheStore['getCategories_v1'];

if (entry && entry.payload && Number(entry.expires_at || 0) > Date.now()) {
  return [{ json: Object.assign({ _cacheStatus: 'HIT' }, entry.payload) }];
}

return [{ json: { _cacheStatus: 'MISS' } }];

const workflowStaticData = $getWorkflowStaticData('global');
const payload = $input.first().json;

if (payload && payload.success) {
  if (!workflowStaticData.presscoCache) {
    workflowStaticData.presscoCache = {};
  }
  workflowStaticData.presscoCache['getCategories_v1'] = {
    payload: JSON.parse(JSON.stringify(payload)),
    cached_at: new Date().toISOString(),
    expires_at: Date.now() + 3600000
  };
}

return [{ json: payload }];
